#define APPROACHING 0;
#define WAITING 1;
#define CROSSING 2;
#define LEFT 3;
#define GATE_UP 0;
#define GATE_DOWN 1;
#define GATE_LOWER_DURATION 2;

var trainState = APPROACHING;
var gateState = GATE_UP;

Train() = approach{trainState = WAITING;} -> TrainWait();

TrainWait() = ifb(gateState == GATE_DOWN) {
    cross{trainState = CROSSING;} -> leave{trainState = LEFT;} -> Train()
} else {
    Wait[1]; TrainWait()
