    lowerGate{gateState = GATE_DOWN;} -> Wait[GATE_LOWER_DURATION]; raiseGate{gateState = GATE_UP;} -> Controller()
} else {
    Wait[1]; Controller()
};

railway_control = Train() ||| Controller();

#define safe (trainState != CROSSING || gateState == GATE_DOWN);

